   160→/// Minimal slider cell with thin track (2px) and small dot knob (8x8).
   161→/// Provides a Figma-like ultra-minimal appearance for the grid size slider.
   162→private final class MinimalSliderCell: NSSliderCell {
   163→    private let trackHeight: CGFloat = 2
   164→    private let knobSize: CGFloat = 8
   165→
   166→    /// Normalized slider position (0.0–1.0).
   167→    private var proportion: CGFloat {
   168→        CGFloat((doubleValue - minValue) / (maxValue - minValue))
   169→    }
   170→
   171→    override func barRect(flipped: Bool) -> NSRect {
   172→        let full = super.barRect(flipped: flipped)
   173→        let y = full.midY - trackHeight / 2
   174→        return NSRect(x: full.origin.x, y: y, width: full.width, height: trackHeight)
   175→    }
   176→
   177→    override func drawBar(inside rect: NSRect, flipped: Bool) {
   178→        let barRect = self.barRect(flipped: flipped)
   179→        let knobX = barRect.origin.x + barRect.width * proportion
   180→
   181→        // Left (filled) portion
   182→        let leftRect = NSRect(x: barRect.origin.x, y: barRect.origin.y,
   183→                              width: knobX - barRect.origin.x, height: barRect.height)
   184→        let leftPath = NSBezierPath(roundedRect: leftRect, xRadius: 1, yRadius: 1)
   185→        NSColor.white.withAlphaComponent(0.4).setFill()
   186→        leftPath.fill()
   187→
   188→        // Right (unfilled) portion
   189→        let rightRect = NSRect(x: knobX, y: barRect.origin.y,
   190→                               width: barRect.maxX - knobX, height: barRect.height)
   191→        let rightPath = NSBezierPath(roundedRect: rightRect, xRadius: 1, yRadius: 1)
   192→        NSColor.white.withAlphaComponent(0.15).setFill()
   193→        rightPath.fill()
   194→    }
   195→
   196→    override func knobRect(flipped: Bool) -> NSRect {
   197→        let barRect = self.barRect(flipped: flipped)
   198→        let knobX = barRect.origin.x + barRect.width * proportion - knobSize / 2
   199→        let knobY = barRect.midY - knobSize / 2
   200→        return NSRect(x: knobX, y: knobY, width: knobSize, height: knobSize)
   201→    }
   202→
   203→    override func drawKnob(_ knobRect: NSRect) {
   204→        let dotRect = NSRect(
   205→            x: knobRect.midX - knobSize / 2,
   206→            y: knobRect.midY - knobSize / 2,
   207→            width: knobSize,
   208→            height: knobSize
   209→        )
   210→        let path = NSBezierPath(ovalIn: dotRect)
   211→        NSColor.white.withAlphaComponent(0.85).setFill()
   212→        path.fill()
   213→    }
   214→}
